#include <stdio.h>
#include <string.h>
#define MAX 1005
int main() {
    int T, N, M, x, y, L;
    char dir[MAX];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d %d %d", &N, &M, &x, &y, &L);
        scanf("%s", dir);
        int headX = x, headY = y;
        int dx[] = {0, 0, -1, 1};
        int dy[] = {-1, 1, 0, 0};
        int dirMap[] = {'U', 'D', 'L', 'R'};
        int currDir = 0;
        for (int i = 0; i < L - 1; i++) {
            for (int j = 0; j < 4; j++) {
                if (dir[i] == dirMap[j]) {
                    currDir = j;
                    break;
                }
            }
            headX += dx[currDir];
            headY += dy[currDir];
        }
        int steps = 0;
        int body[MAX][2];
        for (int i = 0; i < L; i++) {
            body[i][0] = headX;
            body[i][1] = headY;
        }
        while (1) {
            headX += dx[currDir];
            headY += dy[currDir];
            steps++;
            if (headX < 1 || headX > N || headY < 1 || headY > M) {
                printf("WALL %d\n", steps);
                break;
            }
            for (int i = 1; i < L; i++) {
                if (body[i][0] == headX && body[i][1] == headY) {
                    printf("BODY %d\n", steps);
                    break;
                }
            }
            for (int i = L - 1; i > 0; i--) {
                body[i][0] = body[i - 1][0];
                body[i][1] = body[i - 1][1];
            }
            body[0][0] = headX;
            body[0][1] = headY;
        }
    }
    return 0;
}

