const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const input = () => lines[idx++];
const T = parseInt(input());
for (let i = 0; i < T; i++) {
    const [N, M, x, y, L] = input().split(' ').map(Number);
    const dir = input();
    let headX = x, headY = y;
    const dx = [0, 0, -1, 1];
    const dy = [-1, 1, 0, 0];
    const dirMap = { 'U': 0, 'D': 1, 'L': 2, 'R': 3 };
    let currDir = 0;
    for (let j = 0; j < L - 1; j++) {
        currDir = dirMap[dir[j]];
        headX += dx[currDir];
        headY += dy[currDir];
    }
    let steps = 0;
    let body = Array(L).fill(0).map(() => [headX, headY]);
    while (true) {
        headX += dx[currDir];
        headY += dy[currDir];
        steps++;
        if (headX < 1 || headX > N || headY < 1 || headY > M) {
            console.log('WALL ' + steps);
            break;
        }
        for (let i = 1; i < L; i++) {
            if (body[i][0] === headX && body[i][1] === headY) {
                console.log('BODY ' + steps);
                break;
            }
        }
        for (let i = L - 1; i > 0; i--) {
            body[i][0] = body[i - 1][0];
            body[i][1] = body[i - 1][1];
        }
        body[0][0] = headX;
        body[0][1] = headY;
    }
}

